<script>
    let lis = document.querySelectorAll('.becoming-list li'),
        grid = document.querySelector('.becoming_grid');

    if (lis && grid) {
        Array.from(lis).forEach(li => {
            li.addEventListener('click', (e) => {
                e.preventDefault();
                let nro = e.currentTarget.getAttribute('data-toggle');
                grid.setAttribute('data-state', nro)
            })
        })
    }
</script>

<script>
    document.addEventListener("DOMContentLoaded", function() {
        const section = document.querySelector("section.get_in_touch");
        if (!section) return;

        const observer = new MutationObserver(() => {
            if (section.querySelector(".gform_confirmation_message")) {
                if (!section.classList.contains("sended")) {
                    section.classList.add("sended");
                    observer.disconnect();
                }
            } else {
                if (section.classList.contains("sended")) {
                    section.classList.remove("sended");
                }
            }
        });

        observer.observe(section, {
            childList: true,
            subtree: true
        });
    });
</script>